export default Header;

import { GoogleGenAI, Type } from "@google/genai";
import { ProposalInput } from "../types";

// Helper to initialize AI
const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateProposalText = async (input: ProposalInput): Promise<string> => {
  const ai = getAI();
  const prompt = `
    당신은 세계 최고의 비즈니스 제안서 작성 전문가입니다.
    다음 정보를 바탕으로 전문적인 제안서 원고를 작성해 주세요.

    [정보]
    - 제안 업체: ${input.myCompanyName}
    - 클라이언트: ${input.clientCompanyName}
    - 클라이언트 분류: ${input.clientIndustry}
    - 제안서 종류: ${input.proposalType}
    - 목적: ${input.objective}
    - 참고 내용: ${input.referenceContent}

    [작성 규칙]
    1. 마크다운 문법(**, #, - 등)을 절대 사용하지 마세요. 순수 텍스트만 사용하세요.
    2. 가독성을 위해 문단 사이에는 반드시 빈 줄을 두 개 넣어주세요.
    3. 서론, 본론(3~4가지 핵심 제안), 결론, 기대효과 순으로 작성하세요.
    4. 각 주요 섹션의 시작 부분에는 "[[SECTION]]" 이라는 구분자를 넣어주세요. (예: [[SECTION]] 제안 배경)
    5. 문체는 정중하고 설득력 있는 '하십시오'체를 사용하세요.
    6. 내용은 약 1500자 내외로 상세하게 작성하세요.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      temperature: 0.7,
      thinkingConfig: { thinkingBudget: 1024 } // Give it some thought for structure
    }
  });

  return response.text || "";
};

export const generateInfographicPrompts = async (text: string): Promise<string[]> => {
  const ai = getAI();
  const prompt = `
    다음 제안서 텍스트를 분석하여, 텍스트 중간에 삽입할 인포그래픽 아이디어 3개를 도출하세요.

    [텍스트]
    ${text.substring(0, 3000)}

    [요청사항]
    JSON 배열 포맷으로 출력하세요. 각 항목은 인포그래픽을 묘사하는 구체적인 프롬프트여야 합니다.
    인포그래픽에 포함될 한국어 텍스트 키워드 1~2개를 반드시 포함해서 묘사하세요.

    예시:
    [
      "상승하는 화살표가 있는 3D 바 차트, 파란색과 흰색 테마, '매출 상승'이라는 텍스트가 차트 위에 적혀있음, 깔끔한 비즈니스 스타일",
      "중앙에 전구 아이콘이 있고 주변에 톱니바퀴가 맞물려 돌아가는 프로세스 다이어그램, '효율성' 텍스트 포함, 현대적인 플랫 디자인"
    ]
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
        responseMimeType: "application/json",
        responseSchema: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
        }
    }
  });

  try {
    const jsonStr = response.text || "[]";
    return JSON.parse(jsonStr);
  } catch (e) {
    console.error("Failed to parse infographic prompts", e);
    return [];
  }
};

export const generateImage = async (imagePrompt: string, isCover: boolean = false): Promise<string | null> => {
  const ai = getAI();

  // Choose model based on quality needs. 
  // Using gemini-3-pro-image-preview for better text rendering capability.
  const model = 'gemini-3-pro-image-preview'; 

  const enhancedPrompt = isCover 
    ? `A professional business proposal cover image (vertical 3:4 aspect ratio). ${imagePrompt}. High quality, corporate aesthetic, photorealistic or high-end 3D render.`
    : `A clean, modern infographic chart or diagram. ${imagePrompt}. White background, professional business color palette (blue, grey, teal). Text in image should be distinct.`;

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: enhancedPrompt,
      config: {
        imageConfig: {
            aspectRatio: isCover ? "3:4" : "16:9",
            imageSize: "1K" 
        }
      }
    });

    // Extract image
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return part.inlineData.data;
      }
    }
    return null;
  } catch (error) {
    console.error("Image generation error:", error);
    return null;
  }
};

import { Document, Packer, Paragraph, TextRun, ImageRun, HeadingLevel, AlignmentType } from "docx";
import { saveAs } from "file-saver";
import { GeneratedContent } from "../types";

export const createAndDownloadDocx = async (content: GeneratedContent, fileName: string) => {
  const children: (Paragraph)[] = [];

  // Helper to convert base64 to buffer (Uint8Array) for docx
  const base64ToUint8Array = (base64: string) => {
    const binaryString = window.atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
  };

  // 1. Cover Page
  if (content.coverImageBase64) {
    children.push(
      new Paragraph({
        children: [
          new ImageRun({
            data: base64ToUint8Array(content.coverImageBase64),
            transformation: {
              width: 600, // Full width approx
              height: 800,
            },
          }),
        ],
        alignment: AlignmentType.CENTER,
      })
    );
    // Page break after cover
    children.push(new Paragraph({ pageBreakBefore: true }));
  }

  // 2. Content
  let infoGraphicIndex = 0;

  // Logic to distribute infographics evenly
  const totalParagraphs = content.paragraphs.length;
  const graphicsCount = content.infographics.length;
  const interval = Math.floor(totalParagraphs / (graphicsCount + 1));
  let nextGraphicAt = interval;

  content.paragraphs.forEach((text, index) => {
    // Check if it's a section header based on our delimiter
    if (text.trim().startsWith("[[SECTION]]")) {
      const cleanHeader = text.replace("[[SECTION]]", "").trim();
      children.push(
        new Paragraph({
          text: cleanHeader,
          heading: HeadingLevel.HEADING_1,
          spacing: { before: 400, after: 200 },
          border: {
             bottom: {
                color: "4F46E5", // Indigo
                space: 1,
                style: "single",
                size: 6
             }
          }
        })
      );
    } else {
        // Regular paragraph with highlighting logic for key terms (simulation)
        // Since we don't have NLP here, we'll highlight the first sentence to simulate "Emphasis"
        // or highlight specific text if it looks like a key metrics.

        const sentences = text.split('.');
        const runs = sentences.map((sentence, sIdx) => {
           if (sentence.trim().length === 0) return new TextRun("");

           // Simple heuristic: Highlight first sentence of very long paragraphs or if it contains specific chars
           const isImportant = sIdx === 0 && sentence.length > 20 && Math.random() > 0.7;

           return new TextRun({
             text: sentence + ".",
             highlight: isImportant ? "yellow" : undefined, // Highlight important parts
             color: isImportant ? "000000" : "333333",
           });
        });

        children.push(
            new Paragraph({
            children: runs,
            spacing: { after: 200, line: 360 }, // 1.5 line spacing approx
            alignment: AlignmentType.JUSTIFIED,
            })
        );
    }

    // Insert Infographic
    if (index === nextGraphicAt && infoGraphicIndex < graphicsCount) {
        const graphic = content.infographics[infoGraphicIndex];
        if (graphic && graphic.imageBase64) {
            children.push(
                new Paragraph({
                    children: [
                        new ImageRun({
                            data: base64ToUint8Array(graphic.imageBase64),
                            transformation: {
                                width: 500,
                                height: 281, // 16:9 aspect
                            }
                        })
                    ],
                    alignment: AlignmentType.CENTER,
                    spacing: { before: 400, after: 400 }
                })
            );
            infoGraphicIndex++;
            nextGraphicAt += interval;
        }
    }
  });

  const doc = new Document({
    sections: [
      {
        properties: {},
        children: children,
      },
    ],
  });

  const blob = await Packer.toBlob(doc);
  saveAs(blob, `${fileName}.docx`);
};

import React, { useState } from 'react';
import { ProposalInput } from '../types';

interface Props {
  onSubmit: (data: ProposalInput) => void;
  isLoading: boolean;
}

const InputForm: React.FC<Props> = ({ onSubmit, isLoading }) => {
  const [formData, setFormData] = useState<ProposalInput>({
    myCompanyName: '',
    clientCompanyName: '',
    clientIndustry: '',
    proposalType: '마케팅 대행 제안서',
    objective: '매출 200% 증대 및 브랜드 인지도 강화',
    referenceContent: '',
  });

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
     const file = e.target.files?.[0];
     if (file) {
       const reader = new FileReader();
       reader.onload = (event) => {
         const text = event.target?.result as string;
         setFormData(prev => ({ ...prev, referenceContent: text }));
       };
       reader.readAsText(file);
     }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit(formData);
  };

  return (
    <form onSubmit={handleSubmit} className="bg-white p-8 rounded-2xl shadow-xl border border-slate-100 space-y-6">
      <h2 className="text-2xl font-bold text-slate-800 mb-6 border-l-4 border-indigo-600 pl-4">제안서 설정</h2>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div>
          <label className="block text-sm font-semibold text-slate-600 mb-2">내 업체명</label>
          <input
            type="text"
            name="myCompanyName"
            required
            className="w-full px-4 py-3 rounded-lg border border-slate-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition"
            placeholder="예: 넥스트 이노베이션"
            value={formData.myCompanyName}
            onChange={handleChange}
          />
        </div>
        <div>
          <label className="block text-sm font-semibold text-slate-600 mb-2">클라이언트 업체명</label>
          <input
            type="text"
            name="clientCompanyName"
            required
            className="w-full px-4 py-3 rounded-lg border border-slate-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition"
            placeholder="예: 태양 물산"
            value={formData.clientCompanyName}
            onChange={handleChange}
          />
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div>
          <label className="block text-sm font-semibold text-slate-600 mb-2">클라이언트 업체 분류</label>
          <input
            type="text"
            name="clientIndustry"
            required
            className="w-full px-4 py-3 rounded-lg border border-slate-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition"
            placeholder="예: 제조/유통"
            value={formData.clientIndustry}
            onChange={handleChange}
          />
        </div>
        <div>
          <label className="block text-sm font-semibold text-slate-600 mb-2">제안서 종류</label>
          <input
            type="text"
            name="proposalType"
            required
            className="w-full px-4 py-3 rounded-lg border border-slate-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition"
            value={formData.proposalType}
            onChange={handleChange}
          />
        </div>
      </div>

      <div>
        <label className="block text-sm font-semibold text-slate-600 mb-2">제안서를 통해 얻고 싶은 것 (Objective)</label>
        <input
          type="text"
          name="objective"
          required
          className="w-full px-4 py-3 rounded-lg border border-slate-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition"
          value={formData.objective}
          onChange={handleChange}
        />
      </div>

      <div>
        <label className="block text-sm font-semibold text-slate-600 mb-2">참고 파일 / 내용</label>
        <div className="space-y-3">
             <input 
                type="file" 
                accept=".txt,.md"
                onChange={handleFileChange}
                className="block w-full text-sm text-slate-500 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-indigo-50 file:text-indigo-700 hover:file:bg-indigo-100 transition"
             />
            <textarea
            name="referenceContent"
            rows={5}
            className="w-full px-4 py-3 rounded-lg border border-slate-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition"
            placeholder="파일이 없다면 여기에 직접 내용을 붙여넣으세요..."
            value={formData.referenceContent}
            onChange={handleChange}
            />
        </div>
      </div>

      <button
        type="submit"
        disabled={isLoading}
        className={`w-full py-4 rounded-xl text-white font-bold text-lg shadow-lg transition transform hover:scale-[1.02] active:scale-95 ${
          isLoading ? 'bg-slate-400 cursor-not-allowed' : 'bg-gradient-to-r from-indigo-600 to-purple-600 hover:shadow-indigo-500/30'
        }`}
      >
        {isLoading ? '혁신적인 제안서 생성 중...' : '제안서 자동 생성 시작'}
      </button>
    </form>
  );
};

export default InputForm;

import React from 'react';
import { ProposalStep } from '../types';
import { FileText, Image, Layout, FileOutput, CheckCircle2, Loader2 } from 'lucide-react';

interface Props {
  currentStep: ProposalStep;
}

const steps = [
  { id: ProposalStep.GENERATING_TEXT, label: '원고 작성', icon: FileText },
  { id: ProposalStep.GENERATING_INFOGRAPHICS, label: '인포그래픽 생성', icon: Image },
  { id: ProposalStep.GENERATING_COVER, label: '표지 디자인', icon: Layout },
  { id: ProposalStep.COMPILING, label: '문서 통합', icon: FileOutput },
];

const ProgressVisualizer: React.FC<Props> = ({ currentStep }) => {
  if (currentStep === ProposalStep.IDLE) return null;

  const getStepStatus = (stepId: ProposalStep) => {
    const stepOrder = steps.findIndex(s => s.id === stepId);
    const currentOrder = steps.findIndex(s => s.id === currentStep);

    // If completed is the state, all are done
    if (currentStep === ProposalStep.COMPLETED) return 'completed';

    if (stepOrder < currentOrder) return 'completed';
    if (stepOrder === currentOrder) return 'active';
    return 'pending';
  };

  return (
    <div className="w-full py-10">
      <div className="relative flex justify-between items-center max-w-3xl mx-auto">
        {/* Connecting Line */}
        <div className="absolute top-1/2 left-0 w-full h-1 bg-slate-200 -z-10 transform -translate-y-1/2 rounded-full"></div>
        <div 
            className="absolute top-1/2 left-0 h-1 bg-indigo-600 -z-10 transform -translate-y-1/2 rounded-full transition-all duration-700"
            style={{ 
                width: currentStep === ProposalStep.COMPLETED ? '100%' : 
                       `${(steps.findIndex(s => s.id === currentStep) / (steps.length - 1)) * 100}%` 
            }}
        ></div>

        {steps.map((step) => {
          const status = getStepStatus(step.id);
          const Icon = step.icon;

          return (
            <div key={step.id} className="flex flex-col items-center group">
              <div 
                className={`w-14 h-14 rounded-full flex items-center justify-center border-4 transition-all duration-500 bg-white
                  ${status === 'completed' ? 'border-indigo-600 text-indigo-600' : 
                    status === 'active' ? 'border-indigo-600 text-indigo-600 scale-110 shadow-lg shadow-indigo-200' : 
                    'border-slate-300 text-slate-300'}`}
              >
                {status === 'completed' ? (
                  <CheckCircle2 className="w-7 h-7" />
                ) : status === 'active' ? (
                  <Loader2 className="w-7 h-7 animate-spin" />
                ) : (
                  <Icon className="w-6 h-6" />
                )}
              </div>
              <span className={`mt-3 text-sm font-bold transition-colors duration-300
                 ${status === 'active' || status === 'completed' ? 'text-indigo-800' : 'text-slate-400'}`}>
                {step.label}
              </span>
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default ProgressVisualizer;

import React from 'react';
import { GeneratedContent } from '../types';
import { FileDown, FileText } from 'lucide-react';

interface Props {
  content: GeneratedContent;
  onDownload: () => void;
}

const Preview: React.FC<Props> = ({ content, onDownload }) => {
  return (
    <div className="space-y-8 animate-fade-in">
        <div className="bg-gradient-to-br from-green-50 to-emerald-50 border border-green-200 p-6 rounded-xl flex items-center justify-between shadow-md">
            <div>
                <h3 className="text-xl font-bold text-green-800 mb-1">제안서 생성 완료!</h3>
                <p className="text-green-700 text-sm">모든 과정이 성공적으로 완료되었습니다. 아래 버튼을 눌러 WORD 파일을 다운로드하세요.</p>
            </div>
            <button 
                onClick={onDownload}
                className="flex items-center space-x-2 bg-green-600 hover:bg-green-700 text-white px-6 py-3 rounded-lg font-bold shadow-lg transition hover:scale-105"
            >
                <FileDown className="w-5 h-5" />
                <span>WORD 다운로드</span>
            </button>
        </div>

      <div className="bg-white p-8 md:p-12 rounded-2xl shadow-2xl border border-slate-200 max-w-4xl mx-auto min-h-[800px]">
        {/* Cover Preview */}
        {content.coverImageBase64 && (
          <div className="mb-12 flex justify-center">
            <div className="relative group perspective-1000">
                <div className="absolute inset-0 bg-black/10 rounded-lg transform translate-x-2 translate-y-2"></div>
                <img 
                    src={`data:image/png;base64,${content.coverImageBase64}`} 
                    alt="Cover" 
                    className="w-[400px] h-[533px] object-cover rounded-lg shadow-xl border border-slate-200 relative z-10" 
                />
                <div className="absolute bottom-[-40px] left-0 w-full text-center text-sm text-slate-400">표지 미리보기 (3:4)</div>
            </div>
          </div>
        )}

        {/* Content Preview */}
        <div className="space-y-6 text-slate-800 leading-relaxed font-light">
           {content.paragraphs.map((para, idx) => {
               const isHeader = para.startsWith("[[SECTION]]");
               const cleanText = para.replace("[[SECTION]]", "");

               // Check if we should show an infographic after this paragraph
               // Simple logic: Distribute generated infographics evenly
               const graphic = content.infographics.find(g => Math.floor(content.paragraphs.length / (content.infographics.length + 1)) * (content.infographics.indexOf(g) + 1) === idx);

               return (
                   <React.Fragment key={idx}>
                       {isHeader ? (
                           <h2 className="text-2xl font-bold text-indigo-900 mt-10 mb-4 pb-2 border-b-2 border-indigo-100">
                               {cleanText}
                           </h2>
                       ) : (
                           <p className="text-base text-slate-700 whitespace-pre-wrap mb-4">
                               {cleanText}
                           </p>
                       )}

                       {graphic && graphic.imageBase64 && (
                           <div className="my-10 p-4 bg-slate-50 rounded-xl border border-slate-100 flex flex-col items-center">
                               <img 
                                src={`data:image/png;base64,${graphic.imageBase64}`} 
                                alt="Infographic" 
                                className="rounded-lg shadow-md max-w-full h-auto max-h-[400px]"
                               />
                               <p className="text-xs text-slate-400 mt-2">자동 생성된 인포그래픽</p>
                           </div>
                       )}
                   </React.Fragment>
               );
           })}
        </div>
      </div>
    </div>
  );
};

export default Preview;

import React, { useState } from 'react';
import Header from './components/Header';
import InputForm from './components/InputForm';
import ProgressVisualizer from './components/ProgressVisualizer';
import Preview from './components/Preview';
import { ProposalInput, ProposalStep, GeneratedContent } from './types';
import { generateProposalText, generateInfographicPrompts, generateImage } from './services/geminiService';
import { createAndDownloadDocx } from './services/docxService';

const App: React.FC = () => {
  const [currentStep, setCurrentStep] = useState<ProposalStep>(ProposalStep.IDLE);
  const [generatedContent, setGeneratedContent] = useState<GeneratedContent | null>(null);
  const [inputData, setInputData] = useState<ProposalInput | null>(null);

  const startGeneration = async (data: ProposalInput) => {
    setInputData(data);
    setCurrentStep(ProposalStep.GENERATING_TEXT);
    setGeneratedContent(null);

    try {
      // 1. Generate Text
      const rawText = await generateProposalText(data);
      const paragraphs = rawText.split('\n\n').filter(p => p.trim() !== '');

      // 2. Generate Infographics
      setCurrentStep(ProposalStep.GENERATING_INFOGRAPHICS);
      const infographicPrompts = await generateInfographicPrompts(rawText);
      const infographicDataList = [];

      // Generate images in parallel or sequence (Sequence to avoid rate limits usually better for demos, but parallel for speed)
      // Let's do parallel 3 max
      const imagePromises = infographicPrompts.slice(0, 3).map(async (prompt, index) => {
          const b64 = await generateImage(prompt, false);
          return {
              id: `info-${index}`,
              prompt,
              imageBase64: b64 || "", // Handle failure gracefully
              positionIndex: index // will serve as relative order
          };
      });
      const infographics = await Promise.all(imagePromises);
      const validInfographics = infographics.filter(i => i.imageBase64 !== "");

      // 3. Generate Cover
      setCurrentStep(ProposalStep.GENERATING_COVER);
      const coverPrompt = `${data.myCompanyName} providing services to ${data.clientCompanyName}. ${data.proposalType}. ${data.clientIndustry} industry theme. Text on cover: '${data.myCompanyName}', '${data.clientCompanyName}', '${data.proposalType}'`;
      const coverBase64 = await generateImage(coverPrompt, true);

      // 4. Compile
      setCurrentStep(ProposalStep.COMPILING);
      const content: GeneratedContent = {
        rawText,
        paragraphs,
        coverImageBase64: coverBase64,
        infographics: validInfographics
      };

      setGeneratedContent(content);
      setCurrentStep(ProposalStep.COMPLETED);

    } catch (error) {
      console.error("Generation failed:", error);
      alert("오류가 발생했습니다. 다시 시도해주세요.");
      setCurrentStep(ProposalStep.IDLE);
    }
  };

  const handleDownload = () => {
    if (generatedContent && inputData) {
      createAndDownloadDocx(generatedContent, `${inputData.clientCompanyName}_제안서`);
    }
  };

  return (
    <div className="min-h-screen pt-24 pb-12 bg-slate-50 flex flex-col items-center">
      <Header />

      <main className="w-full max-w-5xl px-4 sm:px-6 lg:px-8 space-y-10">

        {/* State: Idle or Input */}
        {currentStep === ProposalStep.IDLE && (
          <div className="animate-fade-in-up">
            <div className="text-center mb-10">
               <h2 className="text-4xl font-extrabold text-slate-900 mb-4">
                 당신의 비즈니스를 위한 <span className="text-indigo-600">완벽한 제안서</span>
               </h2>
               <p className="text-lg text-slate-600 max-w-2xl mx-auto">
                 AI가 원고 작성부터 디자인, 워드 파일 생성까지 자동으로 처리합니다.
                 몇 가지 정보만 입력하고 결과를 확인하세요.
               </p>
            </div>
            <InputForm onSubmit={startGeneration} isLoading={false} />
          </div>
        )}

        {/* State: Processing */}
        {currentStep !== ProposalStep.IDLE && currentStep !== ProposalStep.COMPLETED && (
           <div className="flex flex-col items-center justify-center min-h-[50vh] animate-fade-in">
             <h2 className="text-3xl font-bold text-slate-800 mb-8">혁신적인 제안서를 만들고 있습니다</h2>
             <ProgressVisualizer currentStep={currentStep} />
             <div className="mt-8 text-slate-500 text-sm animate-pulse">
               이 과정은 약 1~2분 정도 소요됩니다. 잠시만 기다려 주세요...
             </div>
           </div>
        )}

        {/* State: Completed */}
        {currentStep === ProposalStep.COMPLETED && generatedContent && (
            <div>
                 <ProgressVisualizer currentStep={currentStep} />
                 <div className="mt-10">
                    <Preview content={generatedContent} onDownload={handleDownload} />
                 </div>
                 <div className="mt-8 text-center">
                    <button 
                      onClick={() => setCurrentStep(ProposalStep.IDLE)}
                      className="text-slate-500 underline hover:text-indigo-600 text-sm"
                    >
                      새로운 제안서 만들기
                    </button>
                 </div>
            </div>
        )}

      </main>
    </div>
  );
};

