import { Document, Packer, Paragraph, TextRun, ImageRun, HeadingLevel, AlignmentType } from "docx";
import { GeneratedContent } from "../types";

export const createAndDownloadDocx = async (content: GeneratedContent, fileName: string) => {
  const children: (Paragraph)[] = [];

  // Helper to convert base64 to buffer (Uint8Array) for docx
  const base64ToUint8Array = (base64: string) => {
    const binaryString = window.atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
  };

  // 1. Cover Page
  if (content.coverImageBase64) {
    children.push(
      new Paragraph({
        children: [
          new ImageRun({
            data: base64ToUint8Array(content.coverImageBase64),
            transformation: {
              width: 600, // Full width approx
              height: 800,
            },
          }),
        ],
        alignment: AlignmentType.CENTER,
      })
    );
    // Page break after cover
    children.push(new Paragraph({ pageBreakBefore: true }));
  }

  // 2. Content
  let infoGraphicIndex = 0;

  // Logic to distribute infographics evenly
  const totalParagraphs = content.paragraphs.length;
  const graphicsCount = content.infographics.length;
  const interval = Math.floor(totalParagraphs / (graphicsCount + 1));
  let nextGraphicAt = interval;

  content.paragraphs.forEach((text, index) => {
    // Check if it's a section header based on our delimiter
    if (text.trim().startsWith("[[SECTION]]")) {
      const cleanHeader = text.replace("[[SECTION]]", "").trim();
      children.push(
        new Paragraph({
          text: cleanHeader,
          heading: HeadingLevel.HEADING_1,
          spacing: { before: 400, after: 200 },
          border: {
             bottom: {
                color: "4F46E5", // Indigo
                space: 1,
                style: "single",
                size: 6
             }
          }
        })
      );
    } else {
        // Regular paragraph with highlighting logic for key terms (simulation)
        // Since we don't have NLP here, we'll highlight the first sentence to simulate "Emphasis"
        // or highlight specific text if it looks like a key metrics.

        const sentences = text.split('.');
        const runs = sentences.map((sentence, sIdx) => {
           if (sentence.trim().length === 0) return new TextRun("");

           // Simple heuristic: Highlight first sentence of very long paragraphs or if it contains specific chars
           const isImportant = sIdx === 0 && sentence.length > 20 && Math.random() > 0.7;

           return new TextRun({
             text: sentence + ".",
             highlight: isImportant ? "yellow" : undefined, // Highlight important parts
             color: isImportant ? "000000" : "333333",
           });
        });

        children.push(
            new Paragraph({
            children: runs,
            spacing: { after: 200, line: 360 }, // 1.5 line spacing approx
            alignment: AlignmentType.JUSTIFIED,
            })
        );
    }

    // Insert Infographic
    if (index === nextGraphicAt && infoGraphicIndex < graphicsCount) {
        const graphic = content.infographics[infoGraphicIndex];
        if (graphic && graphic.imageBase64) {
            children.push(
                new Paragraph({
                    children: [
                        new ImageRun({
                            data: base64ToUint8Array(graphic.imageBase64),
                            transformation: {
                                width: 500,
                                height: 281, // 16:9 aspect
                            }
                        })
                    ],
                    alignment: AlignmentType.CENTER,
                    spacing: { before: 400, after: 400 }
                })
            );
            infoGraphicIndex++;
            nextGraphicAt += interval;
        }
    }
  });

  const doc = new Document({
    sections: [
      {
        properties: {},
        children: children,
      },
    ],
  });

  const blob = await Packer.toBlob(doc);

  // Native download method instead of file-saver
  const url = window.URL.createObjectURL(blob);
  const anchor = document.createElement("a");
  anchor.href = url;
  anchor.download = `${fileName}.docx`;
  document.body.appendChild(anchor);
  anchor.click();
  document.body.removeChild(anchor);
  window.URL.revokeObjectURL(url);
};

import * as pdfjsLib from 'pdfjs-dist';
