      temperature: 0.75, // Creative for better copywriting
      thinkingConfig: { thinkingBudget: 4096 } // Increased budget for deep analysis and long content
    }
  });

  return response.text || "";
};

export const generateInfographicPrompts = async (text: string): Promise<string[]> => {
  const ai = getAI();
  const prompt = `
    다음 제안서 텍스트를 분석하여, 텍스트의 핵심 내용을 시각적으로 설명할 수 있는 인포그래픽 아이디어 3개를 도출하세요.

    [텍스트]
    ${text.substring(0, 6000)}

    [요청사항]
    JSON 배열 포맷으로 출력하세요. 각 항목은 인포그래픽을 묘사하는 구체적인 프롬프트여야 합니다.
    인포그래픽 이미지 안에 포함될 한국어 텍스트 키워드(단어 1~2개)를 반드시 포함해서 묘사하세요.

    예시:
    [
      "상승하는 화살표가 있는 3D 바 차트, 파란색과 흰색 테마, '매출 급증'이라는 한글 텍스트가 차트 위에 적혀있음, 깔끔한 비즈니스 스타일, 고화질 렌더링",
      "중앙에 전구 아이콘이 있고 주변에 톱니바퀴가 맞물려 돌아가는 프로세스 다이어그램, '혁신 솔루션'이라는 한글 텍스트 포함, 현대적인 플랫 디자인"
    ]
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
        responseMimeType: "application/json",
        responseSchema: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
        }
    }
  });

  try {
    const jsonStr = response.text || "[]";
    return JSON.parse(jsonStr);
  } catch (e) {
    console.error("Failed to parse infographic prompts", e);
    return [];
  }
};

export const generateImage = async (imagePrompt: string, isCover: boolean = false): Promise<string | null> => {
  const ai = getAI();

  // Use pro model for better text rendering in images
  const model = 'gemini-3-pro-image-preview'; 

  const enhancedPrompt = isCover 
    ? `A professional business proposal cover image (vertical 3:4 aspect ratio). ${imagePrompt}. High quality, corporate aesthetic, photorealistic or high-end 3D render, minimal text, elegant design.`
    : `A clean, modern infographic chart or diagram. ${imagePrompt}. White background, professional business color palette (blue, navy, grey, teal). The text in the image must be legible. High resolution.`;

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: enhancedPrompt,
      config: {
        imageConfig: {
            aspectRatio: isCover ? "3:4" : "16:9",
            imageSize: "1K" 
        }
      }
    });

    // Extract image
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return part.inlineData.data;
      }
    }
    return null;
  } catch (error) {
    console.error("Image generation error:", error);
    return null;
  }
};

import { Document, Packer, Paragraph, TextRun, ImageRun, HeadingLevel, AlignmentType, Table, TableRow, TableCell, BorderStyle, WidthType } from "docx";
import { GeneratedContent } from "../types";

export const createAndDownloadDocx = async (content: GeneratedContent, fileName: string) => {
  const children: (Paragraph | Table)[] = [];

  // Helper to convert base64 to buffer (Uint8Array) for docx
  const base64ToUint8Array = (base64: string) => {
    try {
      // Remove data URL prefix if present (e.g., "data:image/png;base64,")
      const base64Data = base64.replace(/^data:image\/\w+;base64,/, "");
      const binaryString = window.atob(base64Data);
      const len = binaryString.length;
      const bytes = new Uint8Array(len);
      for (let i = 0; i < len; i++) {
        bytes[i] = binaryString.charCodeAt(i);
      }
      return bytes;
    } catch (e) {
      console.error("Base64 decode error", e);
      return new Uint8Array(0);
    }
  };

  // 1. Cover Page
  if (content.coverImageBase64) {
    children.push(
      new Paragraph({
        children: [
          new ImageRun({
            data: base64ToUint8Array(content.coverImageBase64),
            transformation: {
              width: 600, // Full width approx
              height: 800,
            },
          }),
        ],
        alignment: AlignmentType.CENTER,
      })
    );
    // Page break after cover
    children.push(new Paragraph({ pageBreakBefore: true }));
  }

  // 2. Content Processing (Markdown-like parser)
  let infoGraphicIndex = 0;

  // Logic to distribute infographics evenly
  const totalParagraphs = content.paragraphs.length;
  const graphicsCount = content.infographics.length;
  const interval = Math.floor(totalParagraphs / (graphicsCount + 1));
  let nextGraphicAt = interval;

  // Combine paragraphs back to a single text to perform multi-line regex for tables
  const fullText = content.rawText;

  // Split content by table blocks first
  // Regex looks for lines starting with | (pipe)
  const parts = fullText.split(/((?:^\|.*\|$\n?)+)/m);

  let pIndex = 0; // Tracking paragraph index for infographic insertion

  parts.forEach((part) => {
    if (!part.trim()) return;

    // Check if this part is a Markdown Table
    if (part.trim().startsWith('|') && part.includes('|') && part.includes('---')) {
      const rows = part.trim().split('\n').filter(r => r.trim() !== '');

      const tableRows: TableRow[] = [];

      rows.forEach((rowStr, rowIndex) => {
        // Skip separator row (e.g. |---|---|)
        if (rowStr.includes('---')) return;

        const cells = rowStr.split('|').filter((c, i, arr) => i !== 0 && i !== arr.length - 1);

        const tableCells = cells.map(cellText => {
            return new TableCell({
                children: [new Paragraph({ 
                    children: [new TextRun({ 
                        text: cellText.trim(), 
                        bold: rowIndex === 0, // Bold header
                        size: 24, // 12pt
                    })],
                    alignment: AlignmentType.CENTER
                })],
                width: {
                    size: 100 / cells.length,
                    type: WidthType.PERCENTAGE,
                },
                shading: rowIndex === 0 ? { fill: "E0E7FF" } : undefined, // Light indigo for header
            });
        });

        tableRows.push(new TableRow({ children: tableCells }));
      });

      if (tableRows.length > 0) {
        children.push(
            new Table({
                rows: tableRows,
                width: {
                    size: 100,
                    type: WidthType.PERCENTAGE,
                },
                borders: {
                    top: { style: BorderStyle.SINGLE, size: 1, color: "aaaaaa" },
                    bottom: { style: BorderStyle.SINGLE, size: 1, color: "aaaaaa" },
                    left: { style: BorderStyle.SINGLE, size: 1, color: "aaaaaa" },
                    right: { style: BorderStyle.SINGLE, size: 1, color: "aaaaaa" },
                    insideHorizontal: { style: BorderStyle.SINGLE, size: 1, color: "aaaaaa" },
                    insideVertical: { style: BorderStyle.SINGLE, size: 1, color: "aaaaaa" },
                }
            })
        );
        children.push(new Paragraph({ text: "" })); // Spacing
      }
    } else {
      // Normal Text Processing
      const lines = part.split('\n');

      lines.forEach((line) => {
          if (!line.trim()) return;

          pIndex++;

          // Check for Section Header
          if (line.trim().startsWith("[[SECTION]]")) {
            const cleanHeader = line.replace("[[SECTION]]", "").trim();
            children.push(
                new Paragraph({
                text: cleanHeader,
                heading: HeadingLevel.HEADING_1,
                spacing: { before: 400, after: 200 },
                border: {
                    bottom: {
                        color: "4F46E5", // Indigo
                        space: 1,
                        style: "single",
                        size: 6
                    }
                }
                })
            );
          } else {
            // Process Bold Syntax (**text**)
            const segments = line.split(/(\*\*.*?\*\*)/g);
            const textRuns: TextRun[] = [];

            segments.forEach(segment => {
                if (segment.startsWith('**') && segment.endsWith('**')) {
                    textRuns.push(new TextRun({
                        text: segment.replace(/\*\*/g, ''),
                        bold: true,
                        color: "111827" // Dark Gray/Black for bold
                    }));
                } else {
                    textRuns.push(new TextRun({
                        text: segment,
                    }));
                }
            });

            // Detect if it looks like a list item
            const isListItem = line.trim().startsWith('- ') || line.trim().match(/^\d+\./);

            children.push(
                new Paragraph({
                    children: textRuns,
                    spacing: { after: 200, line: 360 }, // 1.5 line spacing approx
                    alignment: AlignmentType.JUSTIFIED,
                    bullet: isListItem ? { level: 0 } : undefined
                })
            );
          }

          // Infographic Insertion Logic
          if (pIndex === nextGraphicAt && infoGraphicIndex < graphicsCount) {
             const graphic = content.infographics[infoGraphicIndex];
             if (graphic && graphic.imageBase64) {
                 children.push(
                     new Paragraph({
                         children: [
                             new ImageRun({
                                 data: base64ToUint8Array(graphic.imageBase64),
                                 transformation: {
                                     width: 500,
                                     height: 281, // 16:9 aspect
                                 }
                             })
                         ],
                         alignment: AlignmentType.CENTER,
                         spacing: { before: 400, after: 400 }
                     })
                 );
                 infoGraphicIndex++;
                 nextGraphicAt += interval;
             }
         }
      });
    }
  });

  // 3. Business Card (Footer)
  if (content.businessCardImageBase64) {
    children.push(new Paragraph({ pageBreakBefore: true })); // Ensure it starts on a new area or just spaced well
    children.push(
        new Paragraph({
            text: "CONTACT INFO",
            heading: HeadingLevel.HEADING_2,
            alignment: AlignmentType.CENTER,
            spacing: { before: 400, after: 200 }
        })
    );
    children.push(
        new Paragraph({
            children: [
                new ImageRun({
                    data: base64ToUint8Array(content.businessCardImageBase64),
                    transformation: {
                        width: 400, // Standard card width approx
                        height: 228, // Standard card aspect
                    }
                })
            ],
            alignment: AlignmentType.CENTER,
            spacing: { before: 200, after: 200 }
        })
    );
  }

  const doc = new Document({
    sections: [
      {
        properties: {},
        children: children,
      },
    ],
  });

  const blob = await Packer.toBlob(doc);

  // Native download method
  const url = window.URL.createObjectURL(blob);
  const anchor = document.createElement("a");
  anchor.href = url;
  anchor.download = `${fileName}.docx`;
  document.body.appendChild(anchor);
  anchor.click();
  document.body.removeChild(anchor);
  window.URL.revokeObjectURL(url);
};

import React, { useState } from 'react';
import Header from './components/Header';
import InputForm from './components/InputForm';
import ProgressVisualizer from './components/ProgressVisualizer';
import Preview from './components/Preview';
import { ProposalInput, ProposalStep, GeneratedContent } from './types';
import { generateProposalText, generateInfographicPrompts, generateImage } from './services/geminiService';
import { createAndDownloadDocx } from './services/docxService';

// Helper for file to base64
const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => resolve(reader.result as string);
    reader.onerror = error => reject(error);
  });
};

const App: React.FC = () => {
  const [currentStep, setCurrentStep] = useState<ProposalStep>(ProposalStep.IDLE);
  const [generatedContent, setGeneratedContent] = useState<GeneratedContent | null>(null);
  const [inputData, setInputData] = useState<ProposalInput | null>(null);

  const startGeneration = async (data: ProposalInput) => {
    setInputData(data);
    setCurrentStep(ProposalStep.GENERATING_TEXT);
    setGeneratedContent(null);

    try {
      // 1. Generate Text
      const rawText = await generateProposalText(data);
      const paragraphs = rawText.split('\n\n').filter(p => p.trim() !== '');

      // 2. Generate Infographics
      setCurrentStep(ProposalStep.GENERATING_INFOGRAPHICS);
      const infographicPrompts = await generateInfographicPrompts(rawText);
      const infographicDataList = [];

      // Generate images in parallel or sequence
      const imagePromises = infographicPrompts.slice(0, 3).map(async (prompt, index) => {
          const b64 = await generateImage(prompt, false);
          return {
              id: `info-${index}`,
              prompt,
              imageBase64: b64 || "", // Handle failure gracefully
              positionIndex: index // will serve as relative order
          };
      });
      const infographics = await Promise.all(imagePromises);
      const validInfographics = infographics.filter(i => i.imageBase64 !== "");

      // 3. Generate Cover
      setCurrentStep(ProposalStep.GENERATING_COVER);
      const coverPrompt = `${data.myCompanyName} providing services to ${data.clientCompanyName}. ${data.proposalType}. ${data.clientIndustry} industry theme. Text on cover: '${data.myCompanyName}', '${data.clientCompanyName}', '${data.proposalType}'`;
      const coverBase64 = await generateImage(coverPrompt, true);

      // Process Business Card if exists
      let businessCardBase64: string | null = null;
      if (data.businessCardFile) {
        businessCardBase64 = await fileToBase64(data.businessCardFile);
      }

      // 4. Compile
      setCurrentStep(ProposalStep.COMPILING);
      const content: GeneratedContent = {
        rawText,
        paragraphs,
        coverImageBase64: coverBase64,
        infographics: validInfographics,
        businessCardImageBase64: businessCardBase64
      };

      setGeneratedContent(content);
      setCurrentStep(ProposalStep.COMPLETED);

    } catch (error) {
      console.error("Generation failed:", error);
      alert("오류가 발생했습니다. 다시 시도해주세요.");
      setCurrentStep(ProposalStep.IDLE);
    }
  };

  const handleDownload = () => {
    if (generatedContent && inputData) {
      createAndDownloadDocx(generatedContent, `${inputData.clientCompanyName}_제안서`);
    }
  };

  return (
    <div className="min-h-screen pt-24 pb-12 bg-slate-50 flex flex-col items-center">
      <Header />

      <main className="w-full max-w-5xl px-4 sm:px-6 lg:px-8 space-y-10">

        {/* State: Idle or Input */}
        {currentStep === ProposalStep.IDLE && (
          <div className="animate-fade-in-up">
            <div className="text-center mb-10">
               <h2 className="text-4xl font-extrabold text-slate-900 mb-4">
                 당신의 비즈니스를 위한 <span className="text-indigo-600">완벽한 제안서</span>
               </h2>
               <p className="text-lg text-slate-600 max-w-2xl mx-auto">
                 AI가 원고 작성부터 디자인, 워드 파일 생성까지 자동으로 처리합니다.
                 몇 가지 정보만 입력하고 결과를 확인하세요.
               </p>
            </div>
            <InputForm onSubmit={startGeneration} isLoading={false} />
          </div>
        )}

        {/* State: Processing */}
        {currentStep !== ProposalStep.IDLE && currentStep !== ProposalStep.COMPLETED && (
           <div className="flex flex-col items-center justify-center min-h-[50vh] animate-fade-in">
             <h2 className="text-3xl font-bold text-slate-800 mb-8">혁신적인 제안서를 만들고 있습니다</h2>
             <ProgressVisualizer currentStep={currentStep} />
             <div className="mt-8 text-slate-500 text-sm animate-pulse">
               이 과정은 약 1~2분 정도 소요됩니다. 잠시만 기다려 주세요...
             </div>
           </div>
        )}

        {/* State: Completed */}
        {currentStep === ProposalStep.COMPLETED && generatedContent && (
            <div>
                 <ProgressVisualizer currentStep={currentStep} />
                 <div className="mt-10">
                    <Preview content={generatedContent} onDownload={handleDownload} />
                 </div>
                 <div className="mt-8 text-center">
                    <button 
                      onClick={() => setCurrentStep(ProposalStep.IDLE)}
                      className="text-slate-500 underline hover:text-indigo-600 text-sm"
                    >
                      새로운 제안서 만들기
                    </button>
                 </div>
            </div>
        )}

      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { ProposalInput } from '../types';
import { parseFile } from '../services/fileParser';
import { FileText, Loader2, Contact, ChevronRight, ChevronLeft, Check } from 'lucide-react';

interface Props {
  onSubmit: (data: ProposalInput) => void;
  isLoading: boolean;
}

const InputForm: React.FC<Props> = ({ onSubmit, isLoading }) => {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<ProposalInput>({
    myCompanyName: '',
    clientCompanyName: '',
    clientIndustry: '',
    proposalType: '마케팅 대행 제안서',
    objective: '매출 200% 증대 및 브랜드 인지도 강화',
    referenceContent: '',
    businessCardFile: null,
  });

  const [isParsingFile, setIsParsingFile] = useState(false);
  const [fileName, setFileName] = useState<string | null>(null);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
     const file = e.target.files?.[0];
     if (file) {
       setIsParsingFile(true);
       setFileName(file.name);
       try {
         const text = await parseFile(file);
         setFormData(prev => ({ ...prev, referenceContent: text }));
       } catch (error) {
         console.error(error);
         alert("파일을 읽어오는 중 오류가 발생했습니다. (지원 형식: PDF, DOCX, TXT, MD)");
         setFileName(null);
       } finally {
         setIsParsingFile(false);
       }
     }
  };

  const handleBusinessCardChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setFormData(prev => ({ ...prev, businessCardFile: file }));
    }
  };

  const nextStep = () => setStep(prev => Math.min(prev + 1, 3));
  const prevStep = () => setStep(prev => Math.max(prev - 1, 1));

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit(formData);
  };

  const renderStepIndicator = () => (
    <div className="flex justify-center mb-8">
      {[1, 2, 3].map((num) => (
        <div key={num} className="flex items-center">
          <div className={`w-10 h-10 rounded-full flex items-center justify-center font-bold text-sm transition-colors ${
            step === num 
              ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-200' 
              : step > num 
                ? 'bg-green-500 text-white' 
                : 'bg-slate-100 text-slate-400'
          }`}>
            {step > num ? <Check className="w-5 h-5" /> : num}
          </div>
          {num < 3 && (
            <div className={`w-12 h-1 mx-2 rounded-full ${step > num ? 'bg-green-500' : 'bg-slate-100'}`} />
          )}
        </div>
      ))}
    </div>
  );

  return (
    <form onSubmit={handleSubmit} className="bg-white p-8 rounded-2xl shadow-xl border border-slate-100 min-h-[500px] flex flex-col justify-between">
      <div>
        <h2 className="text-2xl font-bold text-slate-800 mb-6 border-l-4 border-indigo-600 pl-4">제안서 설정</h2>
        {renderStepIndicator()}

        {step === 1 && (
          <div className="space-y-6 animate-fade-in">
             <h3 className="text-lg font-semibold text-slate-700 mb-4">기본 정보 입력</h3>
             <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="block text-sm font-semibold text-slate-600 mb-2">내 업체명</label>
                  <input
                    type="text"
                    name="myCompanyName"
                    autoFocus
                    className="w-full px-4 py-3 rounded-lg border border-slate-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition"
                    placeholder="예: 넥스트 이노베이션"
                    value={formData.myCompanyName}
                    onChange={handleChange}
                  />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-600 mb-2">클라이언트 업체명</label>
                  <input
                    type="text"
                    name="clientCompanyName"
                    className="w-full px-4 py-3 rounded-lg border border-slate-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition"
                    placeholder="예: 태양 물산"
                    value={formData.clientCompanyName}
                    onChange={handleChange}
                  />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-600 mb-2">클라이언트 업체 분류</label>
                  <input
                    type="text"
                    name="clientIndustry"
                    className="w-full px-4 py-3 rounded-lg border border-slate-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition"
                    placeholder="예: 제조/유통"
                    value={formData.clientIndustry}
                    onChange={handleChange}
                  />
                </div>
             </div>
          </div>
        )}

        {step === 2 && (
          <div className="space-y-6 animate-fade-in">
            <h3 className="text-lg font-semibold text-slate-700 mb-4">제안 목표 설정</h3>
            <div>
              <label className="block text-sm font-semibold text-slate-600 mb-2">제안서 종류</label>
              <input
                type="text"
                name="proposalType"
                autoFocus
                className="w-full px-4 py-3 rounded-lg border border-slate-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition"
                value={formData.proposalType}
                onChange={handleChange}
              />
            </div>
            <div>
              <label className="block text-sm font-semibold text-slate-600 mb-2">제안서를 통해 얻고 싶은 것 (Objective)</label>
              <input
                type="text"
                name="objective"
                className="w-full px-4 py-3 rounded-lg border border-slate-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition"
                value={formData.objective}
                onChange={handleChange}
              />
            </div>
          </div>
        )}

        {step === 3 && (
          <div className="space-y-6 animate-fade-in">
            <h3 className="text-lg font-semibold text-slate-700 mb-4">참고 자료 및 명함</h3>
            <div>
                <label className="block text-sm font-semibold text-slate-600 mb-2">참고 파일 / 내용</label>
                <div className="space-y-3">
                    <div className="relative">
                        <input 
                            type="file" 
                            accept=".txt,.md,.pdf,.docx,.doc"
                            onChange={handleFileChange}
                            className="block w-full text-sm text-slate-500 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-indigo-50 file:text-indigo-700 hover:file:bg-indigo-100 transition disabled:opacity-50"
                            disabled={isParsingFile || isLoading}
                        />
                        {isParsingFile && (
                            <div className="absolute right-0 top-1/2 -translate-y-1/2 pr-4 flex items-center text-sm text-indigo-600 font-medium">
                                <Loader2 className="w-4 h-4 animate-spin mr-2" />
                                파일 분석 중...
                            </div>
                        )}
                    </div>
                    {fileName && !isParsingFile && (
                        <div className="flex items-center text-xs text-slate-500 pl-1">
                            <FileText className="w-3 h-3 mr-1" />
                            <span>{fileName} 내용이 로드되었습니다.</span>
                        </div>
                    )}
                    <textarea
                    name="referenceContent"
                    rows={6}
                    className="w-full px-4 py-3 rounded-lg border border-slate-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition disabled:bg-slate-50"
                    placeholder="파일 내용을 자동으로 불러오거나 직접 입력하세요..."
                    value={formData.referenceContent}
                    onChange={handleChange}
                    disabled={isParsingFile}
                    />
                </div>
            </div>

            <div>
                <label className="block text-sm font-semibold text-slate-600 mb-2">명함 이미지 (선택)</label>
                <div className="relative border-2 border-dashed border-slate-200 rounded-lg p-4 hover:bg-slate-50 transition">
                    <input 
                        type="file" 
                        accept="image/*"
                        onChange={handleBusinessCardChange}
                        className="block w-full text-sm text-slate-500 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-indigo-50 file:text-indigo-700 hover:file:bg-indigo-100 transition disabled:opacity-50"
                        disabled={isLoading}
                    />
                    {formData.businessCardFile && (
                        <div className="flex items-center text-xs text-slate-500 pl-4 mt-2">
                            <Contact className="w-3 h-3 mr-1" />
                            <span>{formData.businessCardFile.name} 선택됨 (제안서 맨 끝에 첨부됩니다)</span>
                        </div>
                    )}
                </div>
            </div>
          </div>
        )}
      </div>

      <div className="mt-8 flex justify-between pt-6 border-t border-slate-100">
        {step > 1 ? (
            <button
                type="button"
                onClick={prevStep}
                disabled={isLoading}
                className="flex items-center px-6 py-3 rounded-lg text-slate-600 font-semibold hover:bg-slate-100 transition"
            >
                <ChevronLeft className="w-5 h-5 mr-1" />
                이전 단계
            </button>
        ) : (
            <div></div> // Spacer
        )}

        {step < 3 ? (
            <button
                type="button"
                onClick={nextStep}
                className="flex items-center px-6 py-3 rounded-lg bg-indigo-600 text-white font-bold shadow-md hover:bg-indigo-700 transition transform hover:scale-105"
            >
                다음 단계
                <ChevronRight className="w-5 h-5 ml-1" />
            </button>
        ) : (
            <button
                type="submit"
                disabled={isLoading || isParsingFile}
                className={`flex items-center px-8 py-3 rounded-lg text-white font-bold text-lg shadow-lg transition transform hover:scale-[1.02] active:scale-95 ${
                (isLoading || isParsingFile) ? 'bg-slate-400 cursor-not-allowed' : 'bg-gradient-to-r from-indigo-600 to-purple-600 hover:shadow-indigo-500/30'
                }`}
            >
                {isLoading ? <Loader2 className="w-5 h-5 animate-spin mr-2" /> : null}
                {isLoading ? '제안서 생성 중...' : '제안서 완성하기'}
            </button>
        )}
      </div>
    </form>
  );
};

export default InputForm;

