    // Simple logic: Insert infographic image tags after H1 sections roughly
    // We will inject a custom placeholder div where images should go, or just append them if logic is too complex for regex
    // Better strategy for Preview: Split by </h1> and insert image

    // However, since we want to render the exact HTML returned + images interleaved:
    const sections = html.split('</h1>');
    let newHtml = "";

    sections.forEach((section, index) => {
        newHtml += section;
        if (index < sections.length - 1) {
            newHtml += '</h1>'; // Add the tag back

            // Inject infographic if available for this section index (roughly)
            // We have usually 6 sections and 3 images. Inject at index 1, 3, 5?
            const graphicIndex = Math.floor((index) / 2);
            if (index % 2 === 1 && graphicIndex < content.infographics.length) {
                 const graphic = content.infographics[graphicIndex];
                 if (graphic && graphic.imageBase64) {
                     newHtml += `
                        <div class="infographic-container" style="margin: 40px 0; text-align: center;">
                            <img src="data:image/png;base64,${graphic.imageBase64}" style="max-width: 100%; border-radius: 8px; box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1);" alt="Infographic" />
                            <p style="color: #94a3b8; font-size: 0.8rem; margin-top: 8px;">AI Generated Visualization</p>
                        </div>
                     `;
                 }
            }
        }
    });

    // Append Business Card
    if (content.businessCardImageBase64) {
        newHtml += `
            <div style="margin-top: 60px; page-break-before: always; border-top: 2px dashed #cbd5e1; padding-top: 40px; text-align: center;">
                <h2 style="color: #334155; margin-bottom: 20px;">Contact Information</h2>
                <img src="data:image/png;base64,${content.businessCardImageBase64}" style="max-width: 400px; box-shadow: 0 10px 15px -3px rgba(0, 0, 0, 0.1); border-radius: 8px;" alt="Business Card" />
            </div>
        `;
    }

    setDisplayHtml(newHtml);
  }, [content]);

  return (
    <div className="space-y-8 animate-fade-in">
        <div className="bg-gradient-to-br from-green-50 to-emerald-50 border border-green-200 p-6 rounded-xl flex items-center justify-between shadow-md">
            <div>
                <h3 className="text-xl font-bold text-green-800 mb-1">제안서 생성 완료!</h3>
                <p className="text-green-700 text-sm">모든 과정이 성공적으로 완료되었습니다. 아래 버튼을 눌러 WORD 파일을 다운로드하세요.</p>
            </div>
            <button 
                onClick={onDownload}
                className="flex items-center space-x-2 bg-green-600 hover:bg-green-700 text-white px-6 py-3 rounded-lg font-bold shadow-lg transition hover:scale-105"
            >
                <FileDown className="w-5 h-5" />
