      const tagName = el.tagName.toLowerCase();

      // H1 (Main Section)
      if (tagName === 'h1') {
        sectionCount++;
        const colorMatch = el.getAttribute('style')?.match(/color:\s*#([0-9a-fA-F]{6})/);
        const color = colorMatch ? colorMatch[1] : "111827";

        result.push(
            new Paragraph({
                text: el.textContent || "",
                heading: HeadingLevel.HEADING_1,
                spacing: { before: 600, after: 300 },
                border: { bottom: { color: "2563eb", space: 1, style: "single", size: 12 } }, // Thicker blue border
                run: { color: color, bold: true }
            })
        );

        // Inject Infographic after H1
        if (sectionCount % 2 === 0 && graphicIndex < content.infographics.length) {
             const graphic = content.infographics[graphicIndex];
             if (graphic && graphic.imageBase64) {
                 result.push(
                     new Paragraph({
                         children: [
                             new ImageRun({
                                 data: base64ToUint8Array(graphic.imageBase64),
                                 transformation: { width: 500, height: 281 }
                             })
                         ],
                         alignment: AlignmentType.CENTER,
                         spacing: { before: 400, after: 400 }
                     })
                 );
                 graphicIndex++;
             }
        }
      } 
      // H2 (Sub Section)
      else if (tagName === 'h2') {
         const colorMatch = el.getAttribute('style')?.match(/color:\s*#([0-9a-fA-F]{6})/);
         const color = colorMatch ? colorMatch[1] : "1e293b";
         result.push(
            new Paragraph({
                text: el.textContent || "",
                heading: HeadingLevel.HEADING_2,
                spacing: { before: 400, after: 200 },
                run: { color: color, bold: true }
            })
         );
      }
      // H3 (Sub-Sub Section)
      else if (tagName === 'h3') {
         const colorMatch = el.getAttribute('style')?.match(/color:\s*#([0-9a-fA-F]{6})/);
         const color = colorMatch ? colorMatch[1] : "1e40af";
         result.push(
            new Paragraph({
                text: el.textContent || "",
                heading: HeadingLevel.HEADING_3,
                spacing: { before: 300, after: 150 },
                run: { color: color, bold: true, italics: false }
            })
         );
      }
      // Paragraphs and Lists
      else if (tagName === 'p' || tagName === 'div' || tagName === 'li') {
        const runs: TextRun[] = [];

        el.childNodes.forEach(child => {
            if (child.nodeType === Node.TEXT_NODE) {
                runs.push(new TextRun({ text: child.textContent || "" }));
            } else if (child.nodeType === Node.ELEMENT_NODE) {
                const childEl = child as HTMLElement;
                const childTag = childEl.tagName.toLowerCase();
                const style = childEl.getAttribute('style') || "";

                const color = style.match(/color:\s*#([0-9a-fA-F]{6})/)?.[1];
                const bgColor = style.match(/background-color:\s*#([0-9a-fA-F]{6})/)?.[1];

                runs.push(new TextRun({
                    text: childEl.textContent || "",
                    bold: childTag === 'strong' || childTag === 'b' || style.includes('font-weight: bold'),
                    color: color,
                    shading: bgColor ? { type: ShadingType.CLEAR, fill: bgColor } : undefined,
                }));
            }
        });

        result.push(
            new Paragraph({
                children: runs,
                spacing: { line: 360, after: 200 },
                alignment: AlignmentType.JUSTIFIED,
                bullet: tagName === 'li' ? { level: 0 } : undefined
            })
        );
      }
      // Tables
      else if (tagName === 'table') {
         const rows = Array.from(el.querySelectorAll('tr'));
         const tableRows: TableRow[] = [];

         rows.forEach((tr, rIndex) => {
             const cells = Array.from(tr.querySelectorAll('td, th'));
             const tableCells = cells.map((td) => {
                 const tdEl = td as HTMLElement;
                 const isHeader = tdEl.tagName.toLowerCase() === 'th';
                 const style = tdEl.getAttribute('style') || "";
                 const bgColor = style.match(/background-color:\s*#([0-9a-fA-F]{6})/)?.[1];
                 const color = style.match(/color:\s*#([0-9a-fA-F]{6})/)?.[1];

                 return new TableCell({
                     children: [new Paragraph({ 
                         children: [new TextRun({ 
                             text: tdEl.textContent?.trim() || "", 
                             bold: isHeader,
                             color: color || (isHeader ? "1e293b" : "334155"),
                         })],
                         alignment: AlignmentType.CENTER 
                     })],
                     shading: (isHeader || bgColor) ? { fill: bgColor || (isHeader ? "F1F5F9" : "FFFFFF") } : undefined,
                     verticalAlign: AlignmentType.CENTER,
                     borders: {
                         top: { style: BorderStyle.SINGLE, size: 1, color: "cbd5e1" },
                         bottom: { style: BorderStyle.SINGLE, size: 1, color: "cbd5e1" },
                         left: { style: BorderStyle.SINGLE, size: 1, color: "cbd5e1" },
                         right: { style: BorderStyle.SINGLE, size: 1, color: "cbd5e1" },
                     }
                 });
             });
             tableRows.push(new TableRow({ children: tableCells }));
         });

         if (tableRows.length > 0) {
             result.push(new Table({
                 rows: tableRows,
                 width: { size: 100, type: WidthType.PERCENTAGE },
                 borders: {
                    top: { style: BorderStyle.SINGLE, size: 1, color: "aaaaaa" },
                    bottom: { style: BorderStyle.SINGLE, size: 1, color: "aaaaaa" },
                    left: { style: BorderStyle.SINGLE, size: 1, color: "aaaaaa" },
                    right: { style: BorderStyle.SINGLE, size: 1, color: "aaaaaa" },
                    insideHorizontal: { style: BorderStyle.SINGLE, size: 1, color: "aaaaaa" },
                    insideVertical: { style: BorderStyle.SINGLE, size: 1, color: "aaaaaa" },
                }
             }));
             result.push(new Paragraph({ text: "" }));
         }
      }
      else if (tagName === 'div' || tagName === 'ul' || tagName === 'ol') {
          el.childNodes.forEach(child => {
              result.push(...parseNodeToDocx(child));
          });
      }
    }

    return result;
  };

  bodyNodes.forEach(node => {
      children.push(...parseNodeToDocx(node));
  });

  // 3. Business Card (Footer)
  if (content.businessCardImageBase64) {
    children.push(new Paragraph({ pageBreakBefore: true }));
    children.push(
        new Paragraph({
            text: "CONTACT INFO",
            heading: HeadingLevel.HEADING_2,
            alignment: AlignmentType.CENTER,
            spacing: { before: 400, after: 200 }
        })
    );
    children.push(
        new Paragraph({
            children: [
                new ImageRun({
                    data: base64ToUint8Array(content.businessCardImageBase64),
                    transformation: { width: 400, height: 228 }
                })
            ],
            alignment: AlignmentType.CENTER,
            spacing: { before: 200, after: 200 }
        })
    );
  }

  const docx = new Document({
    sections: [{
        properties: {},
        children: children,
    }],
  });

  const blob = await Packer.toBlob(docx);
  const url = window.URL.createObjectURL(blob);
  const anchor = document.createElement("a");
  anchor.href = url;
  anchor.download = `${fileName}.docx`;
  document.body.appendChild(anchor);
  anchor.click();
  document.body.removeChild(anchor);
  window.URL.revokeObjectURL(url);
};

import React, { useState } from 'react';
import { ProposalInput } from '../types';
import { parseFile } from '../services/fileParser';
import { FileText, Loader2, Contact, ChevronRight, ChevronLeft, Check, UploadCloud } from 'lucide-react';

interface Props {
  onSubmit: (data: ProposalInput) => void;
  isLoading: boolean;
}

const InputForm: React.FC<Props> = ({ onSubmit, isLoading }) => {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<ProposalInput>({
    myCompanyName: '',
    clientCompanyName: '',
    clientIndustry: '',
    proposalType: '마케팅 대행 제안서',
    objective: '매출 200% 증대 및 브랜드 인지도 강화',
    referenceContent: '',
    businessCardFile: null,
  });

  const [isParsingFile, setIsParsingFile] = useState(false);
  const [fileName, setFileName] = useState<string | null>(null);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
     const file = e.target.files?.[0];
     if (file) {
       setIsParsingFile(true);
       setFileName(file.name);
       try {
         const text = await parseFile(file);
         setFormData(prev => ({ ...prev, referenceContent: text }));
       } catch (error) {
         console.error(error);
         alert("파일을 읽어오는 중 오류가 발생했습니다. (지원 형식: PDF, DOCX, TXT, MD)");
         setFileName(null);
       } finally {
         setIsParsingFile(false);
       }
     }
  };

  const handleBusinessCardChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setFormData(prev => ({ ...prev, businessCardFile: file }));
    }
  };

  const nextStep = () => setStep(prev => Math.min(prev + 1, 3));
  const prevStep = () => setStep(prev => Math.max(prev - 1, 1));

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit(formData);
  };

  const renderStepIndicator = () => (
    <div className="flex justify-center mb-8">
      {[1, 2, 3].map((num) => (
        <div key={num} className="flex items-center">
          <div className={`w-10 h-10 rounded-full flex items-center justify-center font-bold text-sm transition-colors duration-300 ${
            step === num 
              ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-200 scale-110' 
              : step > num 
                ? 'bg-green-500 text-white' 
                : 'bg-slate-100 text-slate-400'
          }`}>
            {step > num ? <Check className="w-5 h-5" /> : num}
          </div>
          {num < 3 && (
            <div className={`w-16 h-1 mx-2 rounded-full transition-colors duration-300 ${step > num ? 'bg-green-500' : 'bg-slate-100'}`} />
          )}
        </div>
      ))}
    </div>
  );

  return (
    <form onSubmit={handleSubmit} className="bg-white p-8 rounded-2xl shadow-xl border border-slate-100 min-h-[550px] flex flex-col justify-between relative overflow-hidden">
      {/* Background decoration */}
      <div className="absolute top-0 right-0 w-64 h-64 bg-indigo-50 rounded-full blur-3xl -z-10 translate-x-1/2 -translate-y-1/2 opacity-60"></div>

      <div>
        <h2 className="text-2xl font-bold text-slate-800 mb-6 border-l-4 border-indigo-600 pl-4 flex items-center justify-between">
            <span>제안서 설정</span>
            <span className="text-sm font-normal text-slate-400">Step {step} of 3</span>
        </h2>
        {renderStepIndicator()}

        {step === 1 && (
          <div className="space-y-6 animate-fade-in">
             <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-sm font-bold text-slate-700">내 업체명</label>
                  <input
                    type="text"
                    name="myCompanyName"
                    autoFocus
                    required
                    className="w-full px-4 py-3 rounded-lg border border-slate-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition shadow-sm"
                    placeholder="예: 넥스트 이노베이션"
                    value={formData.myCompanyName}
                    onChange={handleChange}
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-bold text-slate-700">클라이언트 업체명</label>
                  <input
                    type="text"
                    name="clientCompanyName"
                    required
                    className="w-full px-4 py-3 rounded-lg border border-slate-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition shadow-sm"
                    placeholder="예: 태양 물산"
                    value={formData.clientCompanyName}
                    onChange={handleChange}
                  />
                </div>
                <div className="space-y-2 md:col-span-2">
                  <label className="text-sm font-bold text-slate-700">클라이언트 산업 분야</label>
                  <input
                    type="text"
                    name="clientIndustry"
                    required
                    className="w-full px-4 py-3 rounded-lg border border-slate-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition shadow-sm"
                    placeholder="예: 제조, 유통, IT 플랫폼 등"
                    value={formData.clientIndustry}
                    onChange={handleChange}
                  />
                </div>
             </div>
          </div>
        )}

        {step === 2 && (
          <div className="space-y-6 animate-fade-in">
            <div className="space-y-4">
              <label className="text-sm font-bold text-slate-700">제안서 종류</label>
              <input
                type="text"
                name="proposalType"
                autoFocus
                required
                className="w-full px-4 py-3 rounded-lg border border-slate-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition shadow-sm"
                placeholder="예: 디지털 마케팅 연간 대행 제안서"
                value={formData.proposalType}
                onChange={handleChange}
              />
            </div>
            <div className="space-y-4">
              <label className="text-sm font-bold text-slate-700">핵심 목표 (Objective)</label>
              <textarea
                name="objective"
                required
                rows={3}
                className="w-full px-4 py-3 rounded-lg border border-slate-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition shadow-sm resize-none"
                placeholder="예: 매출 200% 증대 및 브랜드 인지도 강화, 신규 고객 1만명 유치"
                value={formData.objective}
                onChange={handleChange}
              />
            </div>
          </div>
        )}

        {step === 3 && (
          <div className="space-y-6 animate-fade-in">
            <div className="space-y-2">
                <label className="flex items-center text-sm font-bold text-slate-700">
                    참고 자료 (필수)
                    <span className="ml-2 px-2 py-0.5 bg-indigo-100 text-indigo-700 text-xs rounded-full">AI가 100% 반영합니다</span>
                </label>
                <div className="space-y-3">
                    <div className="relative group">
                        <input 
                            type="file" 
                            accept=".txt,.md,.pdf,.docx,.doc"
                            onChange={handleFileChange}
                            className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
                            disabled={isParsingFile || isLoading}
                        />
                        <div className="flex items-center justify-center w-full px-4 py-4 border-2 border-dashed border-slate-300 rounded-lg group-hover:bg-slate-50 group-hover:border-indigo-400 transition">
                            <UploadCloud className="w-5 h-5 text-slate-400 mr-2 group-hover:text-indigo-500" />
                            <span className="text-sm text-slate-500 group-hover:text-indigo-600 font-medium">
                                {isParsingFile ? '파일 분석 중...' : '클릭하여 파일 업로드 (PDF, DOCX, TXT)'}
                            </span>
                        </div>
                    </div>
                    {fileName && !isParsingFile && (
                        <div className="flex items-center text-xs text-green-600 font-medium bg-green-50 p-2 rounded">
                            <FileText className="w-3 h-3 mr-1" />
                            <span>{fileName} 내용이 로드되었습니다.</span>
                        </div>
                    )}
                    <textarea
                    name="referenceContent"
                    rows={6}
                    className="w-full px-4 py-3 rounded-lg border border-slate-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition disabled:bg-slate-50 text-sm"
                    placeholder="파일 내용을 자동으로 불러오거나, 이곳에 직접 제안서에 들어갈 핵심 내용을 붙여넣으세요. (이 내용을 바탕으로 제안서가 작성됩니다)"
                    value={formData.referenceContent}
                    onChange={handleChange}
                    disabled={isParsingFile}
                    />
                </div>
            </div>

            <div className="space-y-2">
                <label className="text-sm font-bold text-slate-700">명함 이미지 (선택)</label>
                <div className="relative border border-slate-200 rounded-lg p-3 flex items-center bg-slate-50">
                    <input 
                        type="file" 
                        accept="image/*"
                        onChange={handleBusinessCardChange}
                        className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                        disabled={isLoading}
                    />
                    <div className="flex items-center w-full">
                        <div className="w-10 h-10 bg-white rounded border border-slate-200 flex items-center justify-center mr-3">
                            <Contact className="w-5 h-5 text-slate-400" />
                        </div>
                        <div className="flex-1">
                             <div className="text-sm font-medium text-slate-700">
                                 {formData.businessCardFile ? formData.businessCardFile.name : "명함 이미지 업로드"}
                             </div>
                             <div className="text-xs text-slate-500">
                                 {formData.businessCardFile ? "제안서 맨 마지막 페이지에 삽입됩니다." : "클릭하여 이미지를 선택하세요."}
                             </div>
                        </div>
                    </div>
                </div>
            </div>
          </div>
        )}
      </div>

      <div className="mt-8 flex justify-between pt-6 border-t border-slate-100">
        {step > 1 ? (
            <button
                type="button"
                onClick={prevStep}
                disabled={isLoading}
                className="flex items-center px-5 py-2.5 rounded-lg text-slate-600 font-semibold hover:bg-slate-100 transition"
            >
                <ChevronLeft className="w-5 h-5 mr-1" />
                이전 단계
            </button>
        ) : (
            <div></div> // Spacer
        )}

        {step < 3 ? (
            <button
                type="button"
                onClick={nextStep}
                className="flex items-center px-6 py-2.5 rounded-lg bg-indigo-600 text-white font-bold shadow-md hover:bg-indigo-700 hover:shadow-lg transition transform hover:-translate-y-0.5"
            >
                다음 단계
                <ChevronRight className="w-5 h-5 ml-1" />
            </button>
        ) : (
            <button
                type="submit"
                disabled={isLoading || isParsingFile}
                className={`flex items-center px-8 py-3 rounded-lg text-white font-bold text-lg shadow-xl transition transform hover:-translate-y-1 ${
                (isLoading || isParsingFile) ? 'bg-slate-400 cursor-not-allowed shadow-none' : 'bg-gradient-to-r from-indigo-600 to-purple-600 hover:shadow-indigo-500/30'
                }`}
            >
                {isLoading ? <Loader2 className="w-5 h-5 animate-spin mr-2" /> : null}
                {isLoading ? '제안서 생성 중...' : '제안서 완성하기'}
            </button>
        )}
      </div>
    </form>
  );
};

